import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import java.lang.reflect.Field;

public class GsonTest {

  @Test
  public void testSerializeNulls_defaultConstructor() throws Exception {
    Gson gson = new Gson();

    // By default, serializeNulls should be false as per DEFAULT_SERIALIZE_NULLS
    assertFalse(gson.serializeNulls());

    // Use reflection to set the private final field serializeNulls to true
    Field serializeNullsField = Gson.class.getDeclaredField("serializeNulls");
    serializeNullsField.setAccessible(true);
    serializeNullsField.set(gson, true);

    // Now serializeNulls method should return true
    assertTrue(gson.serializeNulls());
  }

  @Test
  public void testSerializeNulls_customConstructorTrue() {
    // Create Gson instance with serializeNulls = true
    Gson gson = new Gson(
      Mockito.mock(com.google.gson.internal.Excluder.class),
      Mockito.mock(com.google.gson.FieldNamingStrategy.class),
      Mockito.mock(java.util.Map.class),
      true, // serializeNulls = true
      false,
      false,
      false,
      false,
      false,
      false,
      true,
      Mockito.mock(com.google.gson.LongSerializationPolicy.class),
      null,
      0,
      0,
      java.util.Collections.emptyList(),
      java.util.Collections.emptyList(),
      java.util.Collections.emptyList(),
      Mockito.mock(com.google.gson.ToNumberStrategy.class),
      Mockito.mock(com.google.gson.ToNumberStrategy.class),
      java.util.Collections.emptyList()
    );

    assertTrue(gson.serializeNulls());
  }

  @Test
  public void testSerializeNulls_customConstructorFalse() {
    // Create Gson instance with serializeNulls = false
    Gson gson = new Gson(
      Mockito.mock(com.google.gson.internal.Excluder.class),
      Mockito.mock(com.google.gson.FieldNamingStrategy.class),
      Mockito.mock(java.util.Map.class),
      false, // serializeNulls = false
      false,
      false,
      false,
      false,
      false,
      false,
      true,
      Mockito.mock(com.google.gson.LongSerializationPolicy.class),
      null,
      0,
      0,
      java.util.Collections.emptyList(),
      java.util.Collections.emptyList(),
      java.util.Collections.emptyList(),
      Mockito.mock(com.google.gson.ToNumberStrategy.class),
      Mockito.mock(com.google.gson.ToNumberStrategy.class),
      java.util.Collections.emptyList()
    );

    assertFalse(gson.serializeNulls());
  }
}
